 1	import type { FC } from 'react';
 2	import { TableIconCell } from 'src/modules/Providers/utils/components/TableCell/TableIconCell';
 3	import type { VmData } from 'src/modules/Providers/views/details/tabs/VirtualMachines/components/VMCellProps';
 4	import {
 5	  getVmPowerState,
 6	  type PowerState,
 7	} from 'src/modules/Providers/views/details/tabs/VirtualMachines/utils/helpers/getVmPowerState';
 8	
 9	import { Tooltip } from '@patternfly/react-core';
10	import { OffIcon, PowerOffIcon, UnknownIcon } from '@patternfly/react-icons';
11	import { useForkliftTranslation } from '@utils/i18n';
12	
13	const VirtualMachinePowerStateCell: FC<{ vmData: VmData }> = ({ vmData }) => {
14	  const { t } = useForkliftTranslation();
15	
16	  const powerState = getVmPowerState(vmData?.vm);
17	  const states: Record<PowerState, [JSX.Element, string, string]> = {
18	    off: [<OffIcon color="grey" key="off" />, t('Powered off'), t('Off')],
19	    on: [<PowerOffIcon color="green" key="on" />, t('Powered on'), t('On')],
20	    unknown: [<UnknownIcon key="unknown" />, t('Unknown power state'), t('Unknown')],
21	  };
22	  const [icon, tooltipText, shortText] = states[powerState] || states.unknown;
23	
24	  return (
25	    <TableIconCell icon={<Tooltip content={tooltipText}>{icon}</Tooltip>}>
26	      {shortText}
27	    </TableIconCell>
28	  );
29	};
30	
31	export default VirtualMachinePowerStateCell;

